m365-182.validationNotes:
# Verify compliance policies assigned
Get-MgDeviceManagementDeviceCompliancePolicy | ForEach-Object {
  $assignments = Get-MgDeviceManagementDeviceCompliancePolicyAssignment -DeviceCompliancePolicyId $_.Id
  [PSCustomObject]@{
    Policy = $_.DisplayName
    Assigned = [bool]$assignments
    GroupCount = $assignments.Count
  }
} | Format-Table

# Check overall compliance status
Get-MgDeviceManagementManagedDevice -All | Group-Object ComplianceState | Select Name, Count | Format-Table
